declare i8 @llvm.umin.i8(i8, i8)
define i8 @test(i8 %x, i8 %a, i8 %b) {
  %m = call i8 @llvm.umin.i8(i8 %a, i8 %b)
  %d = lshr i8 %x, %m
  ret i8 %d
}

define i8 @test(i8 %x, i8 %a, i8 %b) {
  %cmp = icmp ult i8 %a, %b
  %m = select i1 %cmp, i8 %a, i8 %b
  %d = lshr i8 %x, %m
  ret i8 %d
}

